"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["50498"],{5143(i){i.exports=JSON.parse('{"tag":{"label":"rating","permalink":"/sysanalyst-kb.github.io/docs/tags/rating","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":2,"items":[{"id":"specialization/telecom-billing","title":"Billing \u0438 Charging \u2014 \u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0432 Telecom","description":"Billing (\u0432\u044B\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0441\u0447\u0435\u0442\u043E\u0432) \u0438 Charging (\u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438) \u2014 \u044F\u0434\u0440\u043E Telecom. Pre-paid \u0441\u0447\u0451\u0442 \u0432 \u043A\u043E\u043D\u0446\u0435 \u043C\u0435\u0441\u044F\u0446\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0442\u0430\u0440\u0438\u0444\u043D\u044B\u0435 \u043F\u043B\u0430\u043D\u044B, CDR (Call Data Records), \u0440\u043E\u0443\u043C\u0438\u043D\u0433, OCS (Online Charging System) \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 CRM.","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-billing"},{"id":"specialization/gamedev-publishing","title":"\u041F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u044F \u0438\u0433\u0440\u044B \u2014 App Store, Google Play, IAP, \u0440\u0435\u0439\u0442\u0438\u043D\u0433","description":"\u041F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u044F \u0438\u0433\u0440\u044B \u0432 App Store \u0438 Google Play \u2014 \u043D\u0435 \xab\u043A\u0438\u043D\u044C \u0431\u0438\u043B\u0434 \u2014 \u0438 \u0433\u043E\u0442\u043E\u0432\u043E\xbb. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0438 IAP-\u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432 \u0432 \u043A\u043E\u043D\u0441\u043E\u043B\u044F\u0445, \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u043D\u043E\u0433\u043E \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0430 (ESRB/PEGI), \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0435 \u043F\u0440\u0430\u0432\u0438\u043B \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B (loot boxes \u0437\u0430\u043F\u0440\u0435\u0449\u0435\u043D\u044B \u0432 \u0440\u044F\u0434\u0435 \u0441\u0442\u0440\u0430\u043D), \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0438 \u0438 \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438. \u0415\u0441\u043B\u0438 \u043D\u0435 \u0437\u043D\u0430\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B \u2014 \u0438\u0433\u0440\u0443 \u043C\u043E\u0433\u0443\u0442 \u043E\u0442\u043A\u043B\u043E\u043D\u0438\u0442\u044C \u043D\u0430 \u0440\u0435\u0432\u044C\u044E \u0438\u043B\u0438 \u0437\u0430\u0431\u0430\u043D\u0438\u0442\u044C \u043F\u043E\u0441\u043B\u0435 \u0440\u0435\u043B\u0438\u0437\u0430. \u041F\u043E\u0442\u0435\u0440\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u043D\u0430 \u0440\u0435\u0432\u044C\u044E: 1\u20137 \u0434\u043D\u0435\u0439 (App Store) / 1\u20133 \u0447\u0430\u0441\u0430 (Google Play).","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-publishing"}],"unlisted":false}}')}}]);